import{_ as e,o as a,c as i,a7 as o}from"./chunks/framework.CxoDX1mN.js";const g=JSON.parse('{"title":"KiCad 8.0.3 Release","description":"The KiCad project is proud to announce the version 8.0.3 bug fix release. The 8.0.3 stable version contains critical bug fixes and other minor improvements since the previous release.","frontmatter":{"description":"The KiCad project is proud to announce the version 8.0.3 bug fix release. The 8.0.3 stable version contains critical bug fixes and other minor improvements since the previous release.","title":"KiCad 8.0.3 Release","readingTime":false,"tag":["宣发","KiCad"],"top":2,"sticky":2},"headers":[],"relativePath":"posts/KiCad-8.0.3-Release.md","filePath":"posts/KiCad-8.0.3-Release.md","lastUpdated":1721814947000}'),s={name:"posts/KiCad-8.0.3-Release.md"},t=o('<h1 id="kicad-8-0-3-release" tabindex="-1">KiCad 8.0.3 Release <a class="header-anchor" href="#kicad-8-0-3-release" aria-label="Permalink to &quot;KiCad 8.0.3 Release&quot;">​</a></h1><p>The KiCad project is proud to announce the version 8.0.3 bug fix release. The 8.0.3 stable version contains critical bug fixes and other minor improvements since the previous release.</p><p>A list of all of the fixed issues since the 8.0.2 release can be found on the KiCad 8.0.3 milestone page. This release contains several critical bug fixes so please consider upgrading as soon as possible.</p><p>Version 8.0.3 is made from the 8.0 branch with some cherry picked changes from the development branch.</p><p>Packages for Windows, macOS, and Linux are available or will be in the very near future. See the KiCad download page for guidance.</p><p>Thank you to all developers, packagers, librarians, document writers, translators, and everyone else who helped make this release possible.</p><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><ul><li><p>Property grid navigation improvements. #16957</p></li><li><p>Make sure color settings are saved when modified. #17864</p></li><li><p>Improve update notice dialog tooltip. #17927</p></li><li><p>Add optional reporting of non-KiCad design import issues.</p></li><li><p>Add OpenGL info to version information.</p></li></ul><h3 id="schematic-editor" tabindex="-1">Schematic Editor <a class="header-anchor" href="#schematic-editor" aria-label="Permalink to &quot;Schematic Editor&quot;">​</a></h3><ul><li><p>Improve symbol instance data file save ordering. #17737</p></li><li><p>Do not show click to start wire cursor for hidden pins. #17145</p></li><li><p>Internationalize pin information when language changes. #17224</p></li></ul>',11),r=[t];function n(l,d,c,p,h,u){return a(),i("div",{"data-pagefind-body":!0},r)}const f=e(s,[["render",n]]);export{g as __pageData,f as default};
